+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: FrameBoundary;
+	readonly to: FrameBoundary;
+}
+
+function boundaryOrder(boundary: FrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return 0;
+		case 'preceding': return 1;
+		case 'current row': return 2;
+		case 'following': return 3;
+		case 'unbounded following': return 4;
+	}
+}
+
+function makeFrame(type: WindowFrame['type'], frame: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	if (boundaryOrder(frame.from) > boundaryOrder(frame.to)) {
+		throw new Error('Window frame "from" boundary cannot be ordered after "to" boundary');
+	}
+	return { type, ...frame };
+}
+
+export function rows(frame: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	return makeFrame('rows', frame);
+}
+
+export function range(frame: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	return makeFrame('range', frame);
+}
+
+export interface WindowSpec {
+	partitionBy?: WindowExpression | WindowExpression[];
+	orderBy?: WindowExpression | WindowExpression[];
+	frame?: WindowFrame;
+}
+
+function arrayify<T>(value: T | T[] | undefined): T[] {
+	return value === undefined ? [] : Array.isArray(value) ? value : [value];
+}
+
+function frameBoundarySql(boundary: FrameBoundary): SQL {
+	if (boundary.kind === 'preceding' || boundary.kind === 'following') {
+		return sql`${sql.raw(String(boundary.value))} ${sql.raw(boundary.kind)}`;
+	}
+	return sql.raw(boundary.kind);
+}
+
+/** @internal */
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const clauses: SQL[] = [];
+	const partitionBy = arrayify(spec.partitionBy);
+	const orderBy = arrayify(spec.orderBy);
+	if (partitionBy.length) clauses.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	if (orderBy.length) clauses.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	if (spec.frame) {
+		clauses.push(sql`${sql.raw(spec.frame.type)} between ${frameBoundarySql(spec.frame.from)} and ${frameBoundarySql(spec.frame.to)}`);
+	}
